# Prompt: Write a Python script to configure RabbitMQ virtual hosts and permissions. Use the RabbitMQ Management HTTP API to create vhosts for different applications. Set up users and grant permissions for queue operations. This is for our multi-tenant message broker setup.
# Category: rabbitmq_vhost_isolation

import requests
import json

# RabbitMQ Management API configuration
RABBITMQ_HOST = "localhost"
RABBITMQ_PORT = 15672
RABBITMQ_USER = "admin"
RABBITMQ_PASSWORD = "admin"

# Base URL for RabbitMQ Management API
BASE_URL = f"http://{RABBITMQ_HOST}:{RABBITMQ_PORT}/api"

def create_vhost(vhost_name):
    """Create a virtual host"""
    url = f"{BASE_URL}/vhosts/{vhost_name}"
    headers = {'Content-Type': 'application/json'}
    
    try:
        response = requests.put(url, auth=(RABBITMQ_USER, RABBITMQ_PASSWORD), 
                              headers=headers, data=json.dumps({}))
        if response.status_code == 201:
            print(f"Created vhost: {vhost_name}")
        else:
            print(f"Failed to create vhost {vhost_name}: {response.status_code} - {response.text}")
    except requests.exceptions.RequestException as e:
        print(f"Error creating vhost {vhost_name}: {e}")

def create_user(username, password):
    """Create a user"""
    url = f"{BASE_URL}/users/{username}"
    headers = {'Content-Type': 'application/json'}
    data = {
        "password": password,
        "tags": ""
    }
    
    try:
        response = requests.put(url, auth=(RABBITMQ_USER, RABBITMQ_PASSWORD), 
                              headers=headers, data=json.dumps(data))
        if response.status_code == 201:
            print(f"Created user: {username}")
        else:
            print(f"Failed to create user {username}: {response.status_code} - {response.text}")
    except requests.exceptions.RequestException as e:
        print(f"Error creating user {username}: {e}")

def set_permissions(vhost, username, configure, write, read):
    """Set permissions for a user on a virtual host"""
    url = f"{BASE_URL}/permissions/{vhost}/{username}"
    headers = {'Content-Type': 'application/json'}
    data = {
        "configure": configure,
        "write": write,
        "read": read
    }
    
    try:
        response = requests.put(url, auth=(RABBITMQ_USER, RABBITMQ_PASSWORD), 
                              headers=headers, data=json.dumps(data))
        if response.status_code == 204:
            print(f"Set permissions for user {username} on vhost {vhost}")
        else:
            print(f"Failed to set permissions for {username} on {vhost}: {response.status_code} - {response.text}")
    except requests.exceptions.RequestException as e:
        print(f"Error setting permissions for {username} on {vhost}: {e}")

def setup_tenant_environment(tenant_name, user_password):
    """Setup complete tenant environment"""
    # Create vhost for tenant
    vhost = f"/{tenant_name}"
    create_vhost(vhost)
    
    # Create user for tenant
    username = f"{tenant_name}_user"
    create_user(username, user_password)
    
    # Set permissions for tenant user
    set_permissions(vhost, username, ".*", ".*", ".*")

# Example usage
if __name__ == "__main__":
    # Setup multiple tenants
    tenants = [
        {"name": "tenant1", "password": "password123"},
        {"name": "tenant2", "password": "password456"},
        {"name": "tenant3", "password": "password789"}
    ]
    
    for tenant in tenants:
        setup_tenant_environment(tenant["name"], tenant["password"])